-- ELKASS Platform 1.0 — migracja zbiorcza, idempotentna
create extension if not exists pgcrypto;
create table if not exists public.projects(id uuid primary key default gen_random_uuid(),slug text unique not null,name text not null,status text not null default 'active',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
insert into public.projects(slug,name) values('elkass','ELKASS Olesno') on conflict(slug) do update set name=excluded.name;
create table if not exists public.admin_profiles(id uuid primary key references auth.users(id) on delete cascade,project_slug text not null default 'elkass',email text not null,display_name text,role text not null default 'employee' check(role in('owner','admin','employee','editor')),is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.products(id text primary key,project_slug text not null default 'elkass',name text not null,brand text,category text,subcategory text,series text,price numeric(12,2) not null default 0,old_price numeric(12,2),badge text,availability text default 'available',image text,status text not null default 'published',show_home boolean not null default true,is_promo boolean not null default false,is_hit boolean not null default false,is_outlet boolean not null default false,is_new boolean not null default false,stock integer not null default 0,product_json jsonb not null default '{}'::jsonb,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.categories(id text primary key,project_slug text not null default 'elkass',name text not null,description text,image text,sort_order integer default 0,is_active boolean default true,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.subcategories(id text primary key,project_slug text not null default 'elkass',category_id text references public.categories(id) on delete cascade,name text not null,image text,sort_order integer default 0,is_active boolean default true,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.brand_items(id uuid primary key default gen_random_uuid(),project_slug text not null default 'elkass',name text not null,logo_url text,website_url text,sort_order integer default 0,is_active boolean default true,created_at timestamptz default now(),updated_at timestamptz default now(),unique(project_slug,name));
create table if not exists public.media_assets(id uuid primary key default gen_random_uuid(),project_slug text not null default 'elkass',name text,title text,role text,type text default 'image',folder text default 'products',url text not null,alt text,meta jsonb default '{}'::jsonb,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.project_settings(id uuid primary key default gen_random_uuid(),project_slug text not null default 'elkass',setting_key text not null,setting_json jsonb not null default '{}'::jsonb,updated_at timestamptz default now(),unique(project_slug,setting_key));
create table if not exists public.home_sections(id text primary key,project_slug text not null default 'elkass',section_key text not null,title text,is_active boolean default true,sort_order integer default 0,settings jsonb default '{}'::jsonb,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.design_themes(id text primary key,project_slug text not null default 'elkass',name text not null,theme_key text not null,message text,decorations boolean default true,theme_json jsonb default '{}'::jsonb,is_active boolean default false,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.customers(id uuid primary key default gen_random_uuid(),project_slug text not null default 'elkass',email text,name text,phone text,address_json jsonb default '{}'::jsonb,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.orders(id uuid primary key default gen_random_uuid(),project_slug text not null default 'elkass',order_number text unique not null,status text not null default 'new',payment_status text not null default 'pending',payment_method text,delivery_method text,customer_id uuid references public.customers(id),customer_json jsonb not null default '{}'::jsonb,total numeric(12,2) not null default 0,notes text,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.order_items(id uuid primary key default gen_random_uuid(),order_id uuid not null references public.orders(id) on delete cascade,product_id text,product_name text not null,quantity integer not null check(quantity>0),unit_price numeric(12,2) not null,total numeric(12,2) not null,product_json jsonb default '{}'::jsonb);
create table if not exists public.cms_revisions(id uuid primary key default gen_random_uuid(),project_slug text not null default 'elkass',entity_type text not null,entity_id text not null,action text not null,payload jsonb default '{}'::jsonb,created_by uuid references auth.users(id),created_at timestamptz default now());
create or replace function public.touch_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$;
do $$ declare t text; begin foreach t in array array['projects','admin_profiles','products','categories','subcategories','brand_items','media_assets','project_settings','home_sections','design_themes','customers','orders'] loop execute format('drop trigger if exists touch_updated_at on public.%I',t); execute format('create trigger touch_updated_at before update on public.%I for each row execute function public.touch_updated_at()',t); end loop; end $$;
create or replace function public.current_elkass_role() returns text language sql stable security definer set search_path=public as $$ select role from public.admin_profiles where id=auth.uid() and is_active=true limit 1 $$;
create or replace function public.is_elkass_staff() returns boolean language sql stable security definer set search_path=public as $$ select coalesce(public.current_elkass_role() in ('owner','admin','employee','editor'),false) $$;
create or replace function public.is_elkass_admin() returns boolean language sql stable security definer set search_path=public as $$ select coalesce(public.current_elkass_role() in ('owner','admin'),false) $$;
do $$ declare t text; begin foreach t in array array['admin_profiles','products','categories','subcategories','brand_items','media_assets','project_settings','home_sections','design_themes','customers','orders','order_items','cms_revisions'] loop execute format('alter table public.%I enable row level security',t); end loop; end $$;
do $$ begin
 drop policy if exists "public products" on public.products; create policy "public products" on public.products for select using(is_active=true and status='published');
 drop policy if exists "public categories" on public.categories; create policy "public categories" on public.categories for select using(is_active=true);
 drop policy if exists "public subcategories" on public.subcategories; create policy "public subcategories" on public.subcategories for select using(is_active=true);
 drop policy if exists "public brands" on public.brand_items; create policy "public brands" on public.brand_items for select using(is_active=true);
 drop policy if exists "public media" on public.media_assets; create policy "public media" on public.media_assets for select using(true);
 drop policy if exists "public settings" on public.project_settings; create policy "public settings" on public.project_settings for select using(true);
 drop policy if exists "public home" on public.home_sections; create policy "public home" on public.home_sections for select using(is_active=true);
 drop policy if exists "public themes" on public.design_themes; create policy "public themes" on public.design_themes for select using(is_active=true);
end $$;
do $$ declare t text; begin foreach t in array array['products','categories','subcategories','brand_items','media_assets','project_settings','home_sections','design_themes','customers','orders','order_items','cms_revisions'] loop execute format('drop policy if exists "staff manage" on public.%I',t); execute format('create policy "staff manage" on public.%I for all to authenticated using(public.is_elkass_staff()) with check(public.is_elkass_staff())',t); end loop; end $$;
drop policy if exists "own profile" on public.admin_profiles; create policy "own profile" on public.admin_profiles for select to authenticated using(id=auth.uid() or public.is_elkass_admin());
drop policy if exists "admins manage profiles" on public.admin_profiles; create policy "admins manage profiles" on public.admin_profiles for all to authenticated using(public.is_elkass_admin()) with check(public.is_elkass_admin());
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('elkass-media','elkass-media',true,10485760,array['image/jpeg','image/png','image/webp','image/avif','image/svg+xml']) on conflict(id) do update set public=true;
drop policy if exists "public read elkass media" on storage.objects; create policy "public read elkass media" on storage.objects for select using(bucket_id='elkass-media');
drop policy if exists "staff upload elkass media" on storage.objects; create policy "staff upload elkass media" on storage.objects for insert to authenticated with check(bucket_id='elkass-media' and public.is_elkass_staff());
drop policy if exists "staff update elkass media" on storage.objects; create policy "staff update elkass media" on storage.objects for update to authenticated using(bucket_id='elkass-media' and public.is_elkass_staff()) with check(bucket_id='elkass-media' and public.is_elkass_staff());
drop policy if exists "admins delete elkass media" on storage.objects; create policy "admins delete elkass media" on storage.objects for delete to authenticated using(bucket_id='elkass-media' and public.is_elkass_admin());
